---计算需要创建的view的数量
local function calculateCreateViewCount(adapter)
    if adapter.view.orientation == Orientation.Vertical then
        local row = adapter.view:getRowSize()
        local height = adapter.view:getHeight()
        local size = adapter:getItemHeight()
        local space = adapter.view:getVerticalSpace()
        local itemH = height * size[1] + size[2]
        local col = math.ceil((height + space) / itemH) + 1
        return row * col
    else
        local width = adapter.view:getWidth()
        local size = adapter:getItemWidth()
        local space = adapter.view:getHorizontalSpace()
        local itemW = width * size[1] + size[2]
        local col = math.ceil((width + space) / itemW)
        return col + 2
    end
end

---计算出第一个显示的item的位置
local function calculateFirstItemPosition(adapter)
    if adapter.view.orientation == Orientation.Vertical then
        local row = adapter.view:getRowSize()
        local size = adapter:getItemHeight()
        local height = adapter.view:getHeight()
        local space = adapter.view:getVerticalSpace()
        local itemH = height * size[1] + size[2]
        local col = math.ceil(-adapter.offset / (itemH + space)) - 1
        local firstItemPos = math.max(row * col + 1, 1)
        if firstItemPos > adapter:getItemCount() - calculateCreateViewCount(adapter) + row then
            return math.min(adapter.firstItemPos, firstItemPos)
        else
            return firstItemPos
        end
    else
        local size = adapter:getItemWidth()
        local height = adapter.view:getWidth()
        local space = adapter.view:getHorizontalSpace()
        local itemW = height * size[1] + size[2]
        local col = math.ceil(-adapter.offset / (itemW + space)) - 1
        local firstItemPos = math.max(col + 1, 1)
        if firstItemPos > adapter:getItemCount() - calculateCreateViewCount(adapter) + 1 then
            return adapter.firstItemPos
        else
            return firstItemPos
        end
    end
end

---重新设置虚拟列表的可滑动的增量值
local function resetVirtualListOffset(adapter, firstItemPos)
    if adapter.view.orientation == Orientation.Vertical then
        local size = adapter:getItemHeight()
        local height = adapter.view:getHeight()
        local itemH = height * size[1] + size[2]
        local space = adapter.view:getVerticalSpace()
        local offset = (firstItemPos - 1) / adapter.view:getRowSize() * (itemH + space)
        adapter.view.root:SetVirtualListOffset(offset)
    else
        local size = adapter:getItemWidth()
        local height = adapter.view:getWidth()
        local itemW = height * size[1] + size[2]
        local space = adapter.view:getHorizontalSpace()
        local offset = (firstItemPos - 1) * (itemW + space)
        adapter.view.root:SetVirtualListOffset(offset)
    end
end

IDataAdapter = class("IDataAdapter")

function IDataAdapter:ctor()
    self.view = nil
    self.data = {}
    self.offset = 0
    self.firstItemPos = 1
end

function IDataAdapter:setView(view)
    self.view = view
    self.view.root:registerScrollEvent(GUIEvent.ScrollMoveChange, function(event)
        if self.offset == event.offset then
            return
        end
        self.offset = event.offset
        ---TODO 需要更新每个item view的坐标 使其坐标变大变小 让scroll能继续滑动
        self:updateUI(false)
    end)
end

function IDataAdapter:updateUI(force, updatePos)
    if not force then
        local newFirstItemPos = calculateFirstItemPosition(self)
        if newFirstItemPos == self.firstItemPos then
            return
        end
        resetVirtualListOffset(self, newFirstItemPos)
        self.firstItemPos = newFirstItemPos
    end
    local needCount = math.min(calculateCreateViewCount(self), #self.data) --需要显示的view数量
    if updatePos ~= nil then
        updatePos = updatePos - self.firstItemPos + 1
    else
        updatePos = 1
    end
    if updatePos > needCount then
        return
    end
    for pos, window in pairs(self.view.items) do
        if pos > updatePos then
            window.root:SetVisible(false)
        end
    end
    for pos = updatePos, needCount do
        self:updateItemUI(pos + self.firstItemPos - 1)
    end
end

---更新第position条数据的UI
function IDataAdapter:updateItemUI(position)
    local window = self.view.items[position - self.firstItemPos + 1]
    local data = self.data[position]
    if window and data then
        window.root:SetVisible(true)
        window:onDataChanged(data)
    end
end

function IDataAdapter:setScrollOffset(offset)
    self.offset = offset
    self.firstItemPos = calculateFirstItemPosition(self)
    resetVirtualListOffset(self, self.firstItemPos)
    self.view.root:SetScrollOffset(offset)
    self:updateUI(true)
end

---必须重写，返回子UI的json文件名
function IDataAdapter:getJsonName()
    return nil
end

---必须重写，返回子UI的class类创建对象
function IDataAdapter:getWindowClass()
    return IGUIWindow
end

---返回数据的数量
function IDataAdapter:getItemCount()
    return #self.data
end

---必须重写，返回子UI的宽度
function IDataAdapter:getItemWidth()
    return { 0, 0 }
end

---必须重写，返回子UI的高度
function IDataAdapter:getItemHeight()
    return { 0, 0 }
end

---设置整个列表的数据
function IDataAdapter:setData(data)
    self.data = data
    self:setScrollOffset(0)
    self:notifyDataChange()
end

---添加多个数据
---@param items table 数据
---@param startPos number 插入的位置
function IDataAdapter:addItems(items, startPos)
    startPos = startPos or #self.data + 1
    local curPos = startPos
    for _, item in pairs(items) do
        self:addItem(item, curPos)
        curPos = curPos + 1
    end
    self:notifyDataChange(startPos)
end

---添加一个数据
---@param item 任何类型 数据
---@param position number 插入的位置
function IDataAdapter:addItem(item, position)
    position = position or #self.data + 1
    position = math.max(math.min(position, #self.data + 1), 1)
    table.insert(self.data, position, item)
    self:notifyDataChange(position)
end

---获取某个item的位置
function IDataAdapter:getItemPosition(item, key)
    for pos, _item in pairs(self.data) do
        if _item[key] == item[key] then
            return pos
        end
    end
    return -1
end

---根据位置position删除item
function IDataAdapter:removePosition(position)
    table.remove(self.data, position)
    self:notifyDataChange(position)
end

---根据item数据删除item
function IDataAdapter:removeItem(item)
    for pos, child in pairs(self.data) do
        if child == item then
            self:removePosition(pos)
            break
        end
    end
end

---清空数据
function IDataAdapter:clearItems()
    self.data = {}
    self:notifyDataChange()
end

---刷新页面
function IDataAdapter:notifyDataChange(startPos)
    if not self:getJsonName() then
        return false
    end
    local needCount = math.min(calculateCreateViewCount(self), #self.data) --需要显示的view数量
    local childCount = self.view:getChildCount() --获取当前view的数量
    if childCount < needCount then
        --如果当前view的数量不够显示的数量，则需要添加
        while childCount < needCount do
            local class = self:getWindowClass()
            local item = class.new(self:getJsonName())
            item:setWidth(self:getItemWidth())
            item:setHeight(self:getItemHeight())
            if self.view:addItem(item, true) then
                childCount = childCount + 1
            end
        end
    end
    if childCount > needCount then
        --如果当前view的数量大于显示的数量，则需要删除
        while childCount > needCount do
            if self.view:removeItem(self.view.items[#self.view.items], true, true) then
                childCount = childCount - 1
            end
        end
    end
    self:updateUI(true, startPos)
end

---刷新单个数据的UI
function IDataAdapter:notifyItemDataChange(item)
    for pos, data in pairs(self.data) do
        if item == data then
            self:updateItemUI(pos)
            break
        end
    end
end